I'm not sure if I'm using the type_caster machinery correctly; in particular, I'm not sure if I'm supposed to do something to either clear or restore the Python error state.

## Reproducible example code

You can see the Travis output [here](https://travis-ci.org/ska-sa/spead2/builds/409538427) and a minimal git repository [here](https://github.com/ska-sa/spead2/tree/d1c5f3e00dbe9583f775df3bae7ee70eacd2a395) (note: use this commit, not master). For convenience the C++ code is copied below:

```c++
#include <pybind11/pybind11.h>

namespace py = pybind11;

class socket_wrapper
{
    int fd;

public:
    socket_wrapper() : fd(-1) {}
    explicit socket_wrapper(int fd) : fd(fd) {}
};

namespace pybind11
{
namespace detail
{

template<>
struct type_caster<socket_wrapper>
{
public:
    PYBIND11_TYPE_CASTER(socket_wrapper, _("socket.socket"));

    bool load(handle src, bool)
    {
        int fd;
        try
        {
            fd = src.attr("fileno")().cast<int>();
        }
        catch (std::exception)
        {
            return false;
        }
        value = socket_wrapper(fd);
        return true;
    }
};

}} // namespace pybind11::detail

PYBIND11_MODULE(hangup, m)
{
    m.def("foo", [](const socket_wrapper &x) {});
    m.def("foo", [](const std::string &x) {});
}
```

